pub fn parse_local_decl(ts: &mut TokenStream) -> Result<Stmt, CompileError> {
    let base_ty = parse_type(ts)?;
    // Standalone struct definition: `struct tag { ... };`
    if ts.check(&TokenKind::Semicolon) {
