        // Cast: (type)expr  vs  parenthesized: (expr)
        if is_type_start(ts) {
            let ty = parse_type(ts)?;
            ts.expect(TokenKind::RParen)?;
            let operand = parse_unary(ts)?;
            let cast = Expr::Cast {
                ty,
                expr: Box::new(operand),
            };
