9	/// Generate add or subtract, dispatching to the appropriate variant.
10	pub fn gen_add_sub(
11	    state: &mut CodegenState,
12	    op: BinOp,
13	    lhs: &Expr,
14	    rhs: &Expr,
15	    gen_expr_fn: GenExprFn,
16	) {
17	    let lhs_ty = expr_type(state, lhs);
18	    let rhs_ty = expr_type(state, rhs);
19	    let lhs_is_ptr = matches!(&lhs_ty, Some(Type::Ptr(_)));
20	    let rhs_is_ptr = matches!(&rhs_ty, Some(Type::Ptr(_)));
