1	//! Pre-pass to collect local variable declarations and allocate stack slots.
2	
3	use tc24r_ast::{Expr, Stmt};
4	use tc24r_codegen_state::CodegenState;
5	
6	/// Walk a block of statements, allocating stack slots for any local
7	/// variable declarations found (including nested scopes).
8	pub fn collect_locals_block(state: &mut CodegenState, stmts: &[Stmt]) {
9	    for stmt in stmts {
10	        collect_locals_stmt(state, stmt);
11	    }
12	}
13	
14	/// Allocate a stack slot for a local declaration, or recurse into
15	/// compound statements to find nested declarations.
16	pub fn collect_locals_stmt(state: &mut CodegenState, stmt: &Stmt) {
17	    match stmt {
18	        Stmt::LocalDecl { name, ty, init } => {
19	            if !state.locals.contains_key(name) {
20	                let alloc = ty.size().max(3); // min 3 (word-aligned)
21	                state.locals_size += alloc;
22	                let offset = -state.locals_size;
23	                state.locals.insert(name.clone(), offset);
24	                state.local_types.insert(name.clone(), ty.clone());
25	            }
26	            if let Some(expr) = init {
27	                scan_expr_locals(state, expr);
28	            }
29	        }
30	        Stmt::If {
31	            cond,
32	            then_body,
33	            else_body,
34	        } => {
35	            scan_expr_locals(state, cond);
36	            collect_locals_block(state, &then_body.stmts);
37	            if let Some(eb) = else_body {
38	                collect_locals_block(state, &eb.stmts);
39	            }
40	        }
41	        Stmt::While { cond, body } => {
42	            scan_expr_locals(state, cond);
43	            collect_locals_block(state, &body.stmts);
44	        }
